   503→		Logger: logger,
   504→		m:      em,
   505→		name:   path.Base(pinPath),
   506→		path:   pinPath,
   507→		key:    key,
   508→		value:  value,
   509→	}
   510→
   511→	m.updateMetrics()
   512→	registerMap(logger, pinPath, m)
   513→
   514→	return m, nil
   515→}
